136→const getTeamType = (
137→  currentTeam: string
138→): {
139→  childTeamType: string;
140→  teamTypeOptions: typeof TEAM_TYPES;
141→} => {
142→  switch (currentTeam) {
143→    case 'BusinessUnit':
144→      return {
145→        childTeamType: 'Division',
146→        teamTypeOptions: TEAM_TYPES,
147→      };
148→
149→    case 'Division':
150→      return {
151→        childTeamType: 'Department',
152→        teamTypeOptions: TEAM_TYPES,
153→      };
154→
155→    case 'Department':
156→      return {
157→        childTeamType: 'Group',
158→        teamTypeOptions: ['Department', 'Group'],
159→      };
160→  }
161→
162→  return {
163→    childTeamType: '',
164→    teamTypeOptions: [],
165→  };
166→};
