  67→import EntityRightPanelVerticalNav from '../../Entity/EntityRightPanel/EntityRightPanelVerticalNav';
  68→import { EntityRightPanelTab } from '../../Entity/EntityRightPanel/EntityRightPanelVerticalNav.interface';
  69→import CustomPropertiesSection from '../../Explore/EntitySummaryPanel/CustomPropertiesSection/CustomPropertiesSection';
  70→import DataQualityTab from '../../Explore/EntitySummaryPanel/DataQualityTab/DataQualityTab';
  71→import { LineageTabContent } from '../../Explore/EntitySummaryPanel/LineageTab';
  72→import { LineageData } from '../../Lineage/Lineage.interface';
  73→import EntityNameModal from '../../Modals/EntityNameModal/EntityNameModal.component';
  74→import { EntityName } from '../../Modals/EntityNameModal/EntityNameModal.interface';
  75→import {
  76→  ColumnDetailPanelProps,
  77→  ColumnFieldUpdate,
  78→  ColumnOrTask,
  79→  TestCaseStatusCounts,
  80→} from './ColumnDetailPanel.interface';
  81→import './ColumnDetailPanel.less';
  82→import { KeyProfileMetrics } from './KeyProfileMetrics';
  83→import { NestedColumnsSection } from './NestedColumnsSection';
  84→import { DataQualityTest } from '../../common/DataQualitySection/DataQualitySection.interface';
  85→
  86→const isColumn = (item: ColumnOrTask | null): item is Column => {
  87→  return item !== null && 'dataType' in item;
  88→};
  89→
  90→export const ColumnDetailPanel = <T extends ColumnOrTask = Column>({
  91→  column,
  92→  tableFqn,
  93→  isOpen,
  94→  onClose,
  95→  onColumnFieldUpdate,
  96→  deleted = false,
  97→  allColumns = [],
  98→  onNavigate,
  99→  tableConstraints = [],
 100→  entityType,
 101→  onColumnsUpdate,
 102→}: ColumnDetailPanelProps<T>) => {
 103→  const { t } = useTranslation();
 104→  const { permissions } = useGenericContext();
 105→
 106→  const previousFqnRef = useRef<string | undefined>();
 107→  const fetchedColumnFqnRef = useRef<string | undefined>();
 108→
 109→  const [isDescriptionLoading, setIsDescriptionLoading] = useState(false);
 110→  const [isTestCaseLoading, setIsTestCaseLoading] = useState(false);
 111→  const [isDisplayNameEditing, setIsDisplayNameEditing] = useState(false);
 112→  const [isColumnDataLoading, setIsColumnDataLoading] = useState(false);
 113→  const [localToast, setLocalToast] = useState<{
 114→    open: boolean;
 115→    message: string;
 116→    type: 'success' | 'error';
 117→  }>({ open: false, message: '', type: 'success' });
 118→  const [activeTab, setActiveTab] = useState<EntityRightPanelTab>(
 119→    EntityRightPanelTab.OVERVIEW
 120→  );
 121→  const [statusCounts, setStatusCounts] = useState<TestCaseStatusCounts>({
 122→    success: 0,
 123→    failed: 0,
 124→    aborted: 0,
 125→    total: 0,
 126→  });
 127→  const [lineageData] = useState<LineageData | null>(null);
 128→  const [isLineageLoading] = useState<boolean>(false);
 129→  const [entityTypeDetail, setEntityTypeDetail] = useState<Type>();
 130→  const [activeColumn, setActiveColumn] = useState<Column>(column);
 131→  const [lineageFilter, setLineageFilter] = useState<'upstream' | 'downstream'>(
 132→    'downstream'
 133→  );
 134→
 135→  const hasEditPermission = useMemo(
 136→    () => ({
 137→      tags: (permissions.EditTags || permissions.EditAll) && !deleted,
 138→      glossaryTerms:
 139→        (permissions.EditGlossaryTerms || permissions.EditAll) && !deleted,
 140→      description:
 141→        (permissions.EditDescription || permissions.EditAll) && !deleted,
 142→      viewAllPermission: permissions.ViewAll,
 143→      customProperties:
 144→        (permissions.EditCustomFields || permissions.EditAll) && !deleted,
 145→      displayName:
 146→        (permissions.EditDisplayName || permissions.EditAll) && !deleted,
 147→    }),
 148→    [permissions, deleted]
 149→  );
 150→
 151→  const hasViewPermission = useMemo(
 152→    () => ({
 153→      customProperties: permissions.ViewAll || permissions.ViewCustomFields,
 154→    }),
 155→    [permissions]
 156→  );
 157→
 158→  const flattenedColumns = useMemo(
 159→    () => flattenColumns(allColumns as Column[]),
 160→    [allColumns]
 161→  );
 162→
 163→  const { actualColumnIndex, isColumnInList } = useMemo(() => {
 164→    if (!activeColumn?.fullyQualifiedName) {
 165→      return {
 166→        actualColumnIndex: 0,
 167→        isColumnInList: flattenedColumns.length > 0,
 168→      };
 169→    }
 170→
 171→    const index = flattenedColumns.findIndex(
 172→      (col) => col.fullyQualifiedName === activeColumn.fullyQualifiedName
 173→    );
 174→
 175→    return {
 176→      actualColumnIndex: index === -1 ? 0 : index,
 177→      isColumnInList: index !== -1,
 178→    };
 179→  }, [activeColumn, flattenedColumns]);
 180→
 181→  const breadcrumbPath = useMemo(() => {
 182→    if (!isColumn(activeColumn)) {
 183→      return [];
 184→    }
 185→
 186→    return buildColumnBreadcrumbPath(activeColumn, allColumns as Column[]);
 187→  }, [activeColumn, allColumns]);
 188→
 189→  const nestedColumns = useMemo(() => {
 190→    if (!isColumn(activeColumn)) {
 191→      return [];
 192→    }
 193→
 194→    return activeColumn.children || [];
 195→  }, [activeColumn]);
 196→
 197→  const dataQualityTests = useMemo(
 198→    (): DataQualityTest[] => [
 199→      { type: 'success', count: statusCounts.success },
 200→      { type: 'aborted', count: statusCounts.aborted },
 201→      { type: 'failed', count: statusCounts.failed },
 202→    ],
 203→    [statusCounts]
 204→  );
 205→
 206→  const classificationTags = useMemo(
 207→    () =>
 208→      activeColumn?.tags?.filter((tag) => tag.source !== TagSource.Glossary) ||
 209→      [],
 210→    [activeColumn?.tags]
 211→  );
 212→
 213→  const isPrimaryKey = useMemo(() => {
 214→    const columnName = activeColumn?.name;
 215→    if (!columnName) {
 216→      return false;
 217→    }
 218→
 219→    return tableConstraints.some(
 220→      (constraint: TableConstraint) =>
 221→        constraint.constraintType === 'PRIMARY_KEY' &&
 222→        constraint.columns?.includes(columnName)
 223→    );
 224→  }, [activeColumn?.name, tableConstraints]);
 225→
 226→  const isPreviousDisabled = !isColumnInList || actualColumnIndex === 0;
 227→  const isNextDisabled =
 228→    !isColumnInList || actualColumnIndex === flattenedColumns.length - 1;
 229→
 230→  const fetchTestCases = useCallback(async () => {
 231→    if (!column?.fullyQualifiedName) {
 232→      setIsTestCaseLoading(false);
 233→
 234→      return;
 235→    }
 236→
 237→    try {
 238→      setIsTestCaseLoading(true);
 239→      const entityLink = generateEntityLink(column.fullyQualifiedName);
 240→
 241→      const response = await listTestCases({
 242→        entityLink,
 243→        includeAllTests: true,
 244→        limit: 100,
 245→        fields: ['testCaseResult', 'incidentId'],
 246→      });
 247→
 248→      const counts = calculateTestCaseStatusCounts(response.data || []);
 249→      setStatusCounts(counts);
 250→    } catch (error) {
 251→      showErrorToast(error as AxiosError);
 252→      setStatusCounts({ success: 0, failed: 0, aborted: 0, total: 0 });
 253→    } finally {
 254→      setIsTestCaseLoading(false);
 255→    }
 256→  }, [column?.fullyQualifiedName]);
 257→
 258→  const fetchColumnDetails = useCallback(async () => {
 259→    const targetFqn = column?.fullyQualifiedName;
 260→    if (!targetFqn || !isOpen || !tableFqn) {
 261→      return;
 262→    }
 263→
 264→    if (
 265→      entityType === EntityType.TABLE &&
 266→      fetchedColumnFqnRef.current !== targetFqn
 267→    ) {
 268→      try {
 269→        setIsColumnDataLoading(true);
 270→        const response = await getTableColumnsByFQN(tableFqn, {
 271→          fields: 'tags,customMetrics,extension,profile',
 272→          limit: PAGE_SIZE_LARGE,
 273→        });
 274→
 275→        const latestColumn = response.data.find(
 276→          (c) => c.fullyQualifiedName === targetFqn
 277→        );
 278→
 279→        if (latestColumn) {
 280→          setActiveColumn((prev) => {
 281→            // Discard stale response if column changed during fetch
 282→            if (prev?.fullyQualifiedName !== targetFqn) {
 283→              return prev;
 284→            }
 285→
 286→            return { ...prev, ...latestColumn } as Column;
 287→          });
 288→        }
 289→
 290→        fetchedColumnFqnRef.current = targetFqn;
 291→
 292→        if (onColumnsUpdate) {
 293→          onColumnsUpdate(response.data);
 294→        }
 295→      } catch (error) {
 296→        showErrorToast(error as AxiosError);
 297→      } finally {
 298→        setIsColumnDataLoading(false);
 299→      }
 300→    }
 301→  }, [column?.fullyQualifiedName, isOpen, entityType, tableFqn, onColumnsUpdate]);
 302→
 303→  const handleNestedColumnClick = useCallback(
 304→    (nestedColumn: Column) => {
 305→      if (!onNavigate) {
 306→        return;
 307→      }
 308→
 309→      const targetIndex = flattenedColumns.findIndex(
 310→        (col) => col.fullyQualifiedName === nestedColumn.fullyQualifiedName
 311→      );
 312→
 313→      const originalIndex = findOriginalColumnIndex(
 314→        nestedColumn as T,
 315→        allColumns ?? []
 316→      );
 317→
 318→      onNavigate(
 319→        nestedColumn as T,
 320→        originalIndex >= 0 ? originalIndex : targetIndex
 321→      );
 322→    },
 323→    [flattenedColumns, allColumns, onNavigate]
 324→  );
 325→
 326→  const handleBreadcrumbClick = useCallback(
 327→    (breadcrumbColumn: Column) => {
 328→      if (!onNavigate) {
 329→        return;
 330→      }
 331→
 332→      const targetIndex = flattenedColumns.findIndex(
 333→        (col) => col.fullyQualifiedName === breadcrumbColumn.fullyQualifiedName
 334→      );
 335→
 336→      const originalIndex = findOriginalColumnIndex(
 337→        breadcrumbColumn as T,
 338→        allColumns ?? []
 339→      );
 340→
 341→      onNavigate(
 342→        breadcrumbColumn as T,
 343→        originalIndex >= 0 ? originalIndex : targetIndex
 344→      );
 345→    },
 346→    [flattenedColumns, allColumns, onNavigate]
 347→  );
 348→
 349→  const performColumnFieldUpdate = useCallback(
 350→    async (
 351→      update: ColumnFieldUpdate,
 352→      successMessageKey: string
 353→    ): Promise<T | undefined> => {
 354→      if (!activeColumn?.fullyQualifiedName) {
 355→        return undefined;
 356→      }
 357→
 358→      const response = onColumnFieldUpdate
 359→        ? await onColumnFieldUpdate(
 360→            activeColumn.fullyQualifiedName,
 361→            update,
 362→            true
 363→          )
 364→        : // Fallback to direct API call for Table entities when used outside GenericProvider
 365→          ((await updateTableColumn(
 366→            activeColumn.fullyQualifiedName,
 367→            update
 368→          )) as T);
 369→
 370→      if (response) {
 371→        setLocalToast({
 372→          open: true,
 373→          message: t('server.update-entity-success', {
 374→            entity: t(successMessageKey),
 375→          }),
 376→          type: 'success',
 377→        });
 378→      }
 379→
 380→      return response;
 381→    },
 382→    [activeColumn?.fullyQualifiedName, t, onColumnFieldUpdate]
 383→  );
 384→
 385→  const handleDescriptionUpdate = useCallback(
 386→    async (newDescription: string) => {
 387→      try {
 388→        setIsDescriptionLoading(true);
 389→        await performColumnFieldUpdate(
 390→          { description: newDescription },
 391→          'label.description'
 392→        );
 393→      } catch (error) {
 394→        setLocalToast({
 395→          open: true,
 396→          message:
 397→            getErrorText(error as AxiosError, t('message.error')) ||
 398→            t('server.entity-updating-error', {
 399→              entity: t('label.description'),
 400→            }),
 401→          type: 'error',
 402→        });
 403→      } finally {
 404→        setIsDescriptionLoading(false);
 405→      }
 406→    },
 407→    [performColumnFieldUpdate, t]
 408→  );
 409→
 410→  // Preserve glossary and tier tags when updating classification tags
 411→  const prepareClassificationTags = useCallback(
 412→    (updatedTags: TagLabel[]): TagLabel[] => {
 413→      if (updatedTags.length === 0) {
 414→        return normalizeTags(
 415→          (activeColumn?.tags ?? []).filter(
 416→            (tag) =>
 417→              tag.source === TagSource.Glossary ||
 418→              (tag.tagFQN?.startsWith('Tier.') ?? false)
 419→          )
 420→        );
 421→      }
 422→
 423→      return normalizeTags(
 424→        (mergeTagsWithGlossary(activeColumn?.tags, updatedTags) ??
 425→          []) as TagLabel[]
 426→      );
 427→    },
 428→    [activeColumn?.tags]
 429→  );
 430→
 431→  const handleTagsUpdate = useCallback(
 432→    async (updatedTags: TagLabel[]) => {
 433→      try {
 434→        const allTags = prepareClassificationTags(updatedTags);
 435→        const response = await performColumnFieldUpdate(
 436→          { tags: allTags },
 437→          'label.tag-plural'
 438→        );
 439→
 440→        if (response) {
 441→          setActiveColumn((prev: Column) => ({
 442→            ...prev,
 443→            tags: response.tags,
 444→          }));
 445→        }
 446→
 447→        return response?.tags;
 448→      } catch (error) {
 449→        setLocalToast({
 450→          open: true,
 451→          message:
 452→            getErrorText(error as AxiosError, t('message.error')) ||
 453→            t('server.entity-updating-error', {
 454→              entity: t('label.tag-plural'),
 455→            }),
 456→          type: 'error',
 457→        });
 458→
 459→        throw error;
 460→      }
 461→    },
 462→    [prepareClassificationTags, performColumnFieldUpdate, t]
