750→export const getExplorePath: (args: {
751→  tab?: string;
752→  search?: string;
753→  extraParameters?: Record<string, unknown>;
754→  isPersistFilters?: boolean;
755→}) => string = ({ tab, search, extraParameters, isPersistFilters = true }) => {
756→  const pathname = ROUTES.EXPLORE_WITH_TAB.replace(
757→    PLACEHOLDER_ROUTE_TAB,
758→    tab ?? ''
759→  );
760→  let paramsObject: Record<string, unknown> = QueryString.parse(
761→    location.search.startsWith('?')
762→      ? location.search.substring(1)
763→      : location.search
764→  );
765→
766→  const { search: paramSearch } = paramsObject;
767→
768→  /**
769→   * persist the filters if isPersistFilters is true
770→   * otherwise only persist the search and passed extra params
771→   * */
772→  if (isPersistFilters) {
773→    if (!isUndefined(search)) {
774→      paramsObject = {
775→        ...paramsObject,
776→        search,
777→      };
778→    }
779→    if (!isUndefined(extraParameters)) {
780→      paramsObject = {
781→        ...paramsObject,
782→        ...extraParameters,
783→      };
784→    }
785→  } else {
786→    paramsObject = {
787→      search: isUndefined(search) ? paramSearch : search,
788→      ...(!isUndefined(extraParameters) ? extraParameters : {}),
789→    };
790→  }
791→
792→  const query = QueryString.stringify(paramsObject);
793→
794→  return `${pathname}?${query}`;
795→};
