28→  data,
29→  columnPart,
30→  fqn,
31→  setExpandedRowKeys,
32→  openColumnDetailPanel,
33→  selectedColumn,
34→}: UseFqnDeepLinkProps<T>) => {
35→  useEffect(() => {
36→    if (!columnPart || !fqn) {
