40→    const fullColumnFqn = fqn;
41→
42→    const parentKeys = getParentKeysToExpand(data, fullColumnFqn);
43→    if (parentKeys.length > 0) {
44→      setExpandedRowKeys((prev) => [...new Set([...prev, ...parentKeys])]);
45→    }
46→
47→    const matchedField = findFieldByFQN(data, fullColumnFqn);
48→    if (matchedField) {
