52→        openColumnDetailPanel(matchedField);
53→      }
54→    }
55→  }, [
56→    columnPart,
57→    fqn,
58→    data,
59→    openColumnDetailPanel,
60→    selectedColumn,
61→    setExpandedRowKeys,
62→  ]);
63→};
