 28→@Slf4j
 29→public class QueryFilterBuilder {
 30→
 31→  private static final String QUERY_KEY = "query";
 32→  private static final String BOOL_KEY = "bool";
 33→  private static final String MUST_KEY = "must";
 34→  private static final String MUST_NOT_KEY = "must_not";
 35→  private static final String SHOULD_KEY = "should";
 36→  private static final String TERM_KEY = "term";
