 45→
 46→  public static String buildDomainAssetsFilter(InheritedFieldQuery query) {
 47→    ObjectNode queryFilter = MAPPER.createObjectNode();
 48→    ObjectNode queryNode = queryFilter.putObject(QUERY_KEY);
 49→    ObjectNode boolNode = queryNode.putObject(BOOL_KEY);
 50→    ArrayNode mustArray = boolNode.putArray(MUST_KEY);
 51→
 52→    addHierarchyCondition(mustArray, query.getFieldPath(), query.getFieldValue());
 53→    addCommonFilters(mustArray, query);
 54→
 55→    // Exclude data products and columns from domain assets
 56→    ArrayNode mustNotArray = boolNode.putArray(MUST_NOT_KEY);
 57→    addEntityTypeExclusions(mustNotArray);
 58→
 59→    return serializeQuery(queryFilter);
 60→  }
