 62→  public static String buildDomainAssetsCountFilter(String fieldPath) {
 63→    ObjectNode queryFilter = MAPPER.createObjectNode();
 64→    ObjectNode queryNode = queryFilter.putObject(QUERY_KEY);
 65→    ObjectNode boolNode = queryNode.putObject(BOOL_KEY);
 66→    ArrayNode mustArray = boolNode.putArray(MUST_KEY);
 67→
 68→    // Must have domains field
